// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---------------------------------------------------------

// Encode the last row's sort key (created_at, id) into an opaque base64 token.
function encodeCursor(row) {
    const payload = JSON.stringify({
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

// Decode a cursor back into { created_at, id }. Throws on anything malformed
// so the caller can turn it into a 400.
function decodeCursor(cursor) {
    let decoded;
    try {
        decoded = Buffer.from(cursor, 'base64url').toString('utf8');
    } catch {
        throw new Error('Invalid cursor encoding');
    }

    let parsed;
    try {
        parsed = JSON.parse(decoded);
    } catch {
        throw new Error('Invalid cursor payload');
    }

    if (
        parsed === null ||
        typeof parsed !== 'object' ||
        typeof parsed.created_at !== 'string' ||
        !Number.isInteger(parsed.id) ||
        Number.isNaN(Date.parse(parsed.created_at))
    ) {
        throw new Error('Invalid cursor contents');
    }

    return { created_at: parsed.created_at, id: parsed.id };
}

// --- Handler ----------------------------------------------------------------

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    const rawLimit = parseInt(req.query.limit, 10);
    const limit = Number.isInteger(rawLimit)
        ? Math.min(Math.max(rawLimit, 1), 100)
        : 20;

    // Decode the cursor up front so a bad token fails fast with a 400.
    let cursor = null;
    if (req.query.after !== undefined) {
        try {
            cursor = decodeCursor(req.query.after);
        } catch {
            return res.status(400).json({ error: 'Invalid pagination cursor' });
        }
    }

    // Build the query. Fetch limit + 1 rows (the N+1 trick) to detect hasMore.
    let sql;
    let params;

    if (cursor) {
        // Keyset predicate matching the ORDER BY (created_at DESC, id DESC).
        // The row tuple comparison: only rows strictly "after" the cursor.
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
              AND (created_at, id) < ($1, $2)
            ORDER BY created_at DESC, id DESC
            LIMIT $3
        `;
        params = [cursor.created_at, cursor.id, limit + 1];
    } else {
        sql = `
            SELECT id, title, content, author_id, created_at
            FROM posts
            WHERE published = true
            ORDER BY created_at DESC, id DESC
            LIMIT $1
        `;
        params = [limit + 1];
    }

    const result = await db.query(sql, params);
    const rows = result.rows;

    // If we got limit + 1, there is at least one more page. Trim the extra row.
    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;

    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1])
        : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}

module.exports = { getPosts, encodeCursor, decodeCursor };
```

## Key points

- **No OFFSET** — the `WHERE (created_at, id) < ($1, $2)` keyset predicate replaces it entirely. The row-value comparison is exactly the right operator for a `created_at DESC, id DESC` sort: it returns every row that sorts strictly after the cursor, with `id` breaking ties when timestamps collide.
- **N+1 trick** — we ask for `limit + 1`; if the extra row comes back, `hasMore = true` and we slice it off before returning.
- **Opaque cursor** — `{created_at, id}` is JSON-serialized and base64url-encoded, so clients treat it as a blob and can't depend on its internal shape.
- **Graceful failure** — `decodeCursor` validates encoding, JSON, types, and date parseability, throwing on any problem; the handler maps that to a `400`.
- **COUNT removed** — no total-count query, so response time is independent of table size.

## Why cursor-based pagination is superior here

1. **Constant-time deep pages.** `OFFSET 1000000` forces Postgres to scan and discard a million rows on every request. A keyset predicate uses an index on `(created_at DESC, id DESC)` to jump straight to the starting point — page 1 and page 50,000 cost the same.
2. **Stable results under writes.** With offsets, a row inserted or deleted while a user paginates shifts every subsequent page, causing skipped or duplicated items. A cursor anchors to a specific `(created_at, id)` position, so concurrent inserts don't corrupt the sequence.
3. **No expensive COUNT.** Offset UIs usually need a total count for "page X of Y," which is a full scan on large tables. Cursor pagination drops it entirely.

One operational note: for best performance, back this with an index matching the sort —

```sql
CREATE INDEX idx_posts_published_keyset
    ON posts (created_at DESC, id DESC)
    WHERE published = true;
```

(`Buffer.base64url` requires Node 16+; if you're on something older, swap to `'base64'` in both helpers.)

