## Cursor-Based Pagination Implementation

### Helper Functions

```javascript
/**
 * Encodes a compound (created_at, id) cursor as a URL-safe base64 string.
 * Using base64url avoids +, /, and = characters that require percent-encoding
 * in query parameters (Node.js 14.18+ / 16.0+ required for 'base64url' encoding).
 */
function encodeCursor(created_at, id) {
    const payload = JSON.stringify({
        // Normalize to ISO string whether pg returns a Date object or a string
        created_at: created_at instanceof Date ? created_at.toISOString() : created_at,
        id,
    });
    return Buffer.from(payload, 'utf8').toString('base64url');
}

/**
 * Decodes a base64url cursor string back to { created_at, id }.
 * Returns null for any malformed, tampered, or structurally invalid input —
 * the caller is responsible for turning null into a 400 response.
 */
function decodeCursor(cursorStr) {
    try {
        const json = Buffer.from(cursorStr, 'base64url').toString('utf8');
        const parsed = JSON.parse(json);

        if (parsed === null || typeof parsed !== 'object') return null;

        // created_at must be a valid ISO timestamp string
        if (typeof parsed.created_at !== 'string') return null;
        if (isNaN(new Date(parsed.created_at).getTime())) return null;

        // id must be a safe integer (adjust validation if your id is a UUID string)
        if (!Number.isInteger(parsed.id) || parsed.id <= 0) return null;

        return { created_at: parsed.created_at, id: parsed.id };
    } catch {
        // Catches base64 decode errors, JSON.parse errors, etc.
        return null;
    }
}
```

